649→    #[test]
650→    fn parse_config_basic() {
651→        let dir = TempDir::new().unwrap();
652→        let config_path = dir.path().join("config.yaml");
653→        fs::write(
654→            &config_path,
655→            r#"
656→defaults:
657→  max_iterations: 200
658→  timeout: 30
659→
660→functions:
661→  "src/auth.ts:validateToken":
662→    max_iterations: 500
663→    timeout: 120
664→    inputs: ./inputs/validateToken/candidates.json
665→  "src/generated/**":
666→    skip: true
667→"#,
668→        )
669→        .unwrap();
670→
671→        let config = parse_config(&config_path).unwrap();
672→        assert_eq!(config.defaults.max_iterations, Some(200));
